// ============================================
// UTILITY
// ============================================
function formatFunding(num) {
  if (num >= 1e9) return '$' + (num / 1e9).toFixed(1) + 'B';
  if (num >= 1e6) return '$' + (num / 1e6).toFixed(0) + 'M';
  if (num >= 1e3) return '$' + (num / 1e3).toFixed(0) + 'K';
  return '$' + num;
}

function formatFundingLong(num) {
  if (num >= 1e9) return '$' + (num / 1e9).toFixed(1) + ' billion';
  if (num >= 1e6) return '$' + (num / 1e6).toFixed(0) + ' million';
  return '$' + num.toLocaleString();
}

// ============================================
// 1. HERO — Funding Counter Animation
// ============================================
function animateCounter() {
  const el = document.querySelector('.hero__funding');
  if (!el) return;
  const target = 155900000000;
  const duration = 2000;
  const start = performance.now();

  function step(now) {
    const elapsed = Math.min(now - start, duration);
    const progress = elapsed / duration;
    // ease-out cubic
    const eased = 1 - Math.pow(1 - progress, 3);
    const current = Math.floor(target * eased);
    el.textContent = '$' + (current / 1e9).toFixed(1) + ' billion';
    if (elapsed < duration) requestAnimationFrame(step);
  }

  // Start after hero fades in
  setTimeout(() => requestAnimationFrame(step), 800);
}

// ============================================
// 2. TOMBSTONE GRAVEYARD GRID
// ============================================
function buildGraveyard() {
  const grid = document.getElementById('graveyard-grid');
  if (!grid) return;

  const fragment = document.createDocumentFragment();
  STARTUPS.forEach((s, i) => {
    const div = document.createElement('div');
    div.className = 'tombstone';
    div.setAttribute('role', 'listitem');
    div.setAttribute('tabindex', '0');
    div.setAttribute('aria-label', s.name + ', ' + s.founded + ' to ' + s.shutdown + ', ' + s.funding);
    div.dataset.index = i;
    div.innerHTML = `
      <div class="tombstone__inner">
        <div class="tombstone__name">${escapeHtml(s.name)}</div>
        <div class="tombstone__years">${s.founded || '?'} – ${s.shutdown}</div>
        <div class="tombstone__funding">${s.funding}</div>
      </div>
    `;
    fragment.appendChild(div);
  });
  grid.appendChild(fragment);

  // Click handler (delegated)
  grid.addEventListener('click', e => {
    const tomb = e.target.closest('.tombstone');
    if (tomb) openModal(STARTUPS[tomb.dataset.index]);
  });
  grid.addEventListener('keydown', e => {
    if (e.key === 'Enter') {
      const tomb = e.target.closest('.tombstone');
      if (tomb) openModal(STARTUPS[tomb.dataset.index]);
    }
  });
}

function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

// Search filter
function setupSearch() {
  const input = document.getElementById('search-input');
  if (!input) return;
  let timeout;
  input.addEventListener('input', () => {
    clearTimeout(timeout);
    timeout = setTimeout(() => {
      const q = input.value.toLowerCase().trim();
      const tombs = document.querySelectorAll('.tombstone');
      tombs.forEach((t, i) => {
        const name = STARTUPS[t.dataset.index].name.toLowerCase();
        t.classList.toggle('tombstone--hidden', q.length > 0 && !name.includes(q));
      });
    }, 150);
  });
}

// ============================================
// 3. SCATTER PLOT (D3)
// ============================================
function buildScatter() {
  const container = document.getElementById('scatter-chart');
  if (!container || typeof d3 === 'undefined') return;

  const filtered = STARTUPS.filter(s => s.fundingNum > 0 && s.yearsSurvived > 0);
  const margin = { top: 30, right: 30, bottom: 60, left: 80 };
  const width = Math.min(container.clientWidth, 1200);
  const height = Math.min(500, width * 0.5);

  const svg = d3.select(container).append('svg')
    .attr('viewBox', `0 0 ${width} ${height}`)
    .attr('preserveAspectRatio', 'xMidYMid meet');

  const x = d3.scaleLinear()
    .domain([0, d3.max(filtered, d => d.yearsSurvived) + 1])
    .range([margin.left, width - margin.right]);

  const y = d3.scaleLog()
    .domain([1e6, d3.max(filtered, d => d.fundingNum) * 1.2])
    .range([height - margin.bottom, margin.top]);

  // X axis
  svg.append('g')
    .attr('transform', `translate(0, ${height - margin.bottom})`)
    .call(d3.axisBottom(x).ticks(10).tickFormat(d => d + 'y'))
    .call(g => g.selectAll('line, path').attr('stroke', '#2a2a32'))
    .call(g => g.selectAll('text').attr('fill', '#8a8680').style('font-size', '11px'));

  // Y axis
  svg.append('g')
    .attr('transform', `translate(${margin.left}, 0)`)
    .call(d3.axisLeft(y).ticks(6, '$.2s'))
    .call(g => g.selectAll('line, path').attr('stroke', '#2a2a32'))
    .call(g => g.selectAll('text').attr('fill', '#8a8680').style('font-size', '11px'));

  // X label
  svg.append('text')
    .attr('x', width / 2).attr('y', height - 10)
    .attr('text-anchor', 'middle')
    .attr('fill', '#5a5854').style('font-size', '12px')
    .text('Years Survived');

  // Y label
  svg.append('text')
    .attr('x', -height / 2).attr('y', 20)
    .attr('transform', 'rotate(-90)')
    .attr('text-anchor', 'middle')
    .attr('fill', '#5a5854').style('font-size', '12px')
    .text('Funding Raised (log scale)');

  // Grid lines
  svg.append('g')
    .attr('transform', `translate(${margin.left}, 0)`)
    .call(d3.axisLeft(y).ticks(6).tickSize(-(width - margin.left - margin.right)).tickFormat(''))
    .call(g => g.selectAll('line').attr('stroke', '#1a1a20').attr('stroke-dasharray', '2,4'))
    .call(g => g.select('.domain').remove());

  // Tooltip
  const tooltip = document.createElement('div');
  tooltip.className = 'scatter-tooltip';
  container.appendChild(tooltip);

  // Dots
  svg.selectAll('circle')
    .data(filtered)
    .join('circle')
    .attr('cx', d => x(d.yearsSurvived))
    .attr('cy', d => y(Math.max(1e6, d.fundingNum)))
    .attr('r', 0)
    .attr('fill', d => SECTOR_COLORS[d.sector] || '#666')
    .attr('opacity', 0.7)
    .attr('cursor', 'pointer')
    .on('mouseenter', function(event, d) {
      d3.select(this).attr('opacity', 1).attr('r', 7);
      tooltip.innerHTML = `<strong>${d.name}</strong><br>${d.funding} · ${d.yearsSurvived}y`;
      tooltip.classList.add('visible');
    })
    .on('mousemove', function(event) {
      const rect = container.getBoundingClientRect();
      tooltip.style.left = (event.clientX - rect.left + 12) + 'px';
      tooltip.style.top = (event.clientY - rect.top - 10) + 'px';
    })
    .on('mouseleave', function() {
      d3.select(this).attr('opacity', 0.7).attr('r', 5);
      tooltip.classList.remove('visible');
    })
    .on('click', function(event, d) { openModal(d); })
    .transition()
    .duration(800)
    .delay((d, i) => i * 3)
    .attr('r', 5);

  // Legend
  const legendEl = document.getElementById('scatter-legend');
  if (legendEl) {
    const sectors = [...new Set(filtered.map(d => d.sector))].sort();
    legendEl.innerHTML = sectors.map(s =>
      `<div class="chart-legend__item">
        <span class="chart-legend__dot" style="background:${SECTOR_COLORS[s] || '#666'}"></span>
        ${s}
      </div>`
    ).join('');
  }
}

// ============================================
// 4. TREEMAP (D3)
// ============================================
function buildTreemap() {
  const container = document.getElementById('treemap-chart');
  if (!container || typeof d3 === 'undefined') return;

  const sectorCounts = d3.rollup(STARTUPS, v => v.length, d => d.sector);
  const data = {
    name: 'root',
    children: Array.from(sectorCounts, ([name, value]) => ({ name, value }))
  };

  const width = Math.min(container.clientWidth, 1200);
  const height = Math.min(550, width * 0.5);

  const root = d3.treemap()
    .size([width, height])
    .padding(3)
    .round(true)
    (d3.hierarchy(data).sum(d => d.value).sort((a, b) => b.value - a.value));

  const svg = d3.select(container).append('svg')
    .attr('viewBox', `0 0 ${width} ${height}`)
    .attr('preserveAspectRatio', 'xMidYMid meet');

  const cell = svg.selectAll('g')
    .data(root.leaves())
    .join('g')
    .attr('transform', d => `translate(${d.x0},${d.y0})`);

  cell.append('rect')
    .attr('class', 'treemap-cell')
    .attr('width', d => d.x1 - d.x0)
    .attr('height', d => d.y1 - d.y0)
    .attr('rx', 4)
    .attr('fill', d => SECTOR_COLORS[d.data.name] || '#555')
    .attr('opacity', 0.8);

  cell.each(function(d) {
    const w = d.x1 - d.x0;
    const h = d.y1 - d.y0;
    const g = d3.select(this);

    if (w > 70 && h > 40) {
      // Wrap text
      const name = d.data.name;
      const fontSize = w > 150 ? 13 : 11;
      g.append('text')
        .attr('class', 'treemap-label')
        .attr('x', w / 2).attr('y', h / 2 - 6)
        .attr('text-anchor', 'middle')
        .style('font-size', fontSize + 'px')
        .text(name.length > 20 ? name.substring(0, 18) + '…' : name);

      g.append('text')
        .attr('class', 'treemap-count')
        .attr('x', w / 2).attr('y', h / 2 + 12)
        .attr('text-anchor', 'middle')
        .style('font-size', '12px')
        .text(d.data.value);
    }
  });
}

// ============================================
// 5. TIMELINE — Stacked Bar (D3)
// ============================================
function buildTimeline() {
  const container = document.getElementById('timeline-chart');
  if (!container || typeof d3 === 'undefined') return;

  // Group by shutdown year + sector
  const yearSector = d3.rollup(STARTUPS, v => v.length, d => d.shutdown, d => d.sector);
  const years = Array.from(yearSector.keys()).sort();
  const sectors = [...new Set(STARTUPS.map(d => d.sector))].sort();

  const stackData = years.map(year => {
    const entry = { year };
    sectors.forEach(s => { entry[s] = yearSector.get(year)?.get(s) || 0; });
    return entry;
  });

  const margin = { top: 20, right: 20, bottom: 60, left: 50 };
  const width = Math.min(container.clientWidth, 1200);
  const height = Math.min(450, width * 0.45);

  const svg = d3.select(container).append('svg')
    .attr('viewBox', `0 0 ${width} ${height}`)
    .attr('preserveAspectRatio', 'xMidYMid meet');

  const x = d3.scaleBand()
    .domain(years)
    .range([margin.left, width - margin.right])
    .padding(0.2);

  const stack = d3.stack().keys(sectors)(stackData);
  const yMax = d3.max(stack[stack.length - 1], d => d[1]);

  const y = d3.scaleLinear()
    .domain([0, yMax]).nice()
    .range([height - margin.bottom, margin.top]);

  // X axis
  svg.append('g')
    .attr('transform', `translate(0, ${height - margin.bottom})`)
    .call(d3.axisBottom(x).tickValues(years.filter((y, i) => i % 2 === 0)))
    .call(g => g.selectAll('line, path').attr('stroke', '#2a2a32'))
    .call(g => g.selectAll('text').attr('fill', '#8a8680').style('font-size', '11px')
      .attr('transform', 'rotate(-45)').attr('text-anchor', 'end'));

  // Y axis
  svg.append('g')
    .attr('transform', `translate(${margin.left}, 0)`)
    .call(d3.axisLeft(y).ticks(6))
    .call(g => g.selectAll('line, path').attr('stroke', '#2a2a32'))
    .call(g => g.selectAll('text').attr('fill', '#8a8680').style('font-size', '11px'));

  // Grid lines
  svg.append('g')
    .attr('transform', `translate(${margin.left}, 0)`)
    .call(d3.axisLeft(y).ticks(6).tickSize(-(width - margin.left - margin.right)).tickFormat(''))
    .call(g => g.selectAll('line').attr('stroke', '#1a1a20').attr('stroke-dasharray', '2,4'))
    .call(g => g.select('.domain').remove());

  // Bars
  svg.selectAll('g.layer')
    .data(stack)
    .join('g')
    .attr('class', 'layer')
    .attr('fill', d => SECTOR_COLORS[d.key] || '#555')
    .selectAll('rect')
    .data(d => d)
    .join('rect')
    .attr('class', 'timeline-bar')
    .attr('x', d => x(d.data.year))
    .attr('width', x.bandwidth())
    .attr('y', height - margin.bottom)
    .attr('height', 0)
    .attr('rx', 1)
    .transition()
    .duration(600)
    .delay((d, i) => i * 20)
    .attr('y', d => y(d[1]))
    .attr('height', d => y(d[0]) - y(d[1]));

  // Y label
  svg.append('text')
    .attr('x', -height / 2).attr('y', 14)
    .attr('transform', 'rotate(-90)')
    .attr('text-anchor', 'middle')
    .attr('fill', '#5a5854').style('font-size', '12px')
    .text('Shutdowns');
}

// ============================================
// 6. WORD CLOUD
// ============================================
function buildWordCloud() {
  const container = document.getElementById('wordcloud-chart');
  if (!container) return;

  const reasonCounts = {};
  STARTUPS.forEach(s => {
    reasonCounts[s.reason] = (reasonCounts[s.reason] || 0) + 1;
  });

  const sorted = Object.entries(reasonCounts).sort((a, b) => b[1] - a[1]);
  const maxCount = sorted[0][1];
  const minSize = 14;
  const maxSize = 64;

  // Color palette for reasons
  const reasonColors = [
    '#c9a96e', '#d4816b', '#b5707a', '#7eb5a0', '#6e9ac9',
    '#a07cc5', '#7aad7e', '#c48cb3', '#8a8fa3', '#5da899',
    '#c97a6e', '#9a8a6e', '#b09570', '#7a8fb5', '#8a9977', '#6b8fa3'
  ];

  container.innerHTML = sorted.map(([reason, count], i) => {
    const size = minSize + (count / maxCount) * (maxSize - minSize);
    const color = reasonColors[i % reasonColors.length];
    const opacity = 0.5 + (count / maxCount) * 0.5;
    return `<span class="wordcloud-word" style="font-size:${size}px; color:${color}; opacity:${opacity}"
      title="${reason}: ${count} startups">${reason}</span>`;
  }).join('');
}

// ============================================
// 7. MODAL
// ============================================
function openModal(startup) {
  const overlay = document.getElementById('modal-overlay');
  if (!overlay) return;

  document.getElementById('modal-name').textContent = startup.name;
  document.querySelector('.modal__years').textContent =
    (startup.founded || '?') + ' – ' + startup.shutdown +
    (startup.yearsSurvived > 0 ? ' · ' + startup.yearsSurvived + ' years' : '');

  document.querySelector('.modal__badges').innerHTML =
    `<span class="badge badge--sector">${escapeHtml(startup.sector)}</span>` +
    `<span class="badge badge--reason">${escapeHtml(startup.reason)}</span>`;

  document.querySelector('.modal__stats').innerHTML = `
    <div>
      <div class="modal__stat-label">Funding</div>
      <div class="modal__stat-value">${startup.funding}</div>
    </div>
    <div>
      <div class="modal__stat-label">City</div>
      <div class="modal__stat-value">${escapeHtml(startup.city)}</div>
    </div>
    <div>
      <div class="modal__stat-label">Employees</div>
      <div class="modal__stat-value">${startup.employees ? startup.employees.toLocaleString() : '—'}</div>
    </div>
  `;

  document.querySelector('.modal__summary').textContent = startup.summary;

  overlay.hidden = false;
  // Force reflow before adding class for transition
  overlay.offsetHeight;
  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';

  // Focus trap
  overlay.querySelector('.modal-close').focus();
}

function closeModal() {
  const overlay = document.getElementById('modal-overlay');
  if (!overlay) return;
  overlay.classList.remove('active');
  document.body.style.overflow = '';
  setTimeout(() => { overlay.hidden = true; }, 300);
}

function setupModal() {
  const overlay = document.getElementById('modal-overlay');
  if (!overlay) return;

  overlay.querySelector('.modal-close').addEventListener('click', closeModal);
  overlay.addEventListener('click', e => {
    if (e.target === overlay) closeModal();
  });
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') closeModal();
  });
}

// ============================================
// INTERSECTION OBSERVER — Scroll Reveals
// ============================================
function setupScrollReveal() {
  // Add fade-in class to sections
  document.querySelectorAll('.section__header, .chart-container, .chart-legend').forEach(el => {
    el.classList.add('fade-in');
  });

  // For browsers without animation-timeline support, use IntersectionObserver
  if (!CSS.supports('animation-timeline', 'scroll()')) {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.style.opacity = '1';
          entry.target.style.transition = 'opacity 0.8s cubic-bezier(0.16, 1, 0.3, 1)';
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.fade-in').forEach(el => {
      el.style.opacity = '0';
      observer.observe(el);
    });
  }

  // Lazy-build charts when they come into view
  const chartObserver = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        const id = entry.target.id;
        if (id === 'scatter-chart' && !entry.target.querySelector('svg')) buildScatter();
        if (id === 'treemap-chart' && !entry.target.querySelector('svg')) buildTreemap();
        if (id === 'timeline-chart' && !entry.target.querySelector('svg')) buildTimeline();
        if (id === 'wordcloud-chart' && !entry.target.children.length) buildWordCloud();
        chartObserver.unobserve(entry.target);
      }
    });
  }, { threshold: 0.05, rootMargin: '200px' });

  ['scatter-chart', 'treemap-chart', 'timeline-chart', 'wordcloud-chart'].forEach(id => {
    const el = document.getElementById(id);
    if (el) chartObserver.observe(el);
  });
}

// ============================================
// INIT
// ============================================
document.addEventListener('DOMContentLoaded', () => {
  animateCounter();
  buildGraveyard();
  setupSearch();
  setupModal();
  setupScrollReveal();
});
